+assert_contains() {
+  local file="$1"
+  local pattern="$2"
+
+  if ! grep -Fq "$pattern" "$file"; then
+    echo "expected $file to contain: $pattern" >&2
+    return 1
+  fi
+}
+
+assert_not_contains() {
+  local file="$1"
+  local pattern="$2"
+
+  if grep -Fq "$pattern" "$file"; then
+    echo "expected $file to omit: $pattern" >&2
+    return 1
+  fi
+}
+
+assert_files_match() {
+  local left="$1"
+  local right="$2"
+
+  if ! cmp -s "$left" "$right"; then
+    echo "expected $left to match $right" >&2
+    return 1
+  fi
+}
+
+assert_file_exists() {
+  local target="$1"
+
+  if [[ ! -f "$target" ]]; then
+    echo "expected file to exist: $target" >&2
+    return 1
+  fi
+}
