+module Main
+
+record SearchRequest = { query : Str }
+record SearchResponse = { summary : Str }
+record WorkflowState = { status : Str }
+record AuditEnvelope = { releaseId : Str, status : Str }
+record Empty = {}
+
+record AuditEvent = {
+  kind : Str,
+  boundary : Str,
+  operation : Str,
+  retentionDays : Int,
+  redactedFields : [Str],
+  rootCause : Str,
+  tracePath : [Str]
+}
+
+record AuditSnapshot = {
+  typedEventKinds : [Str],
+  routeEvent : AuditEvent,
+  toolEvent : AuditEvent,
+  workflowEvent : AuditEvent,
+  secretEvent : AuditEvent,
+  missingSecretBlame : Str
+}
+
+guide AuditGuide = {
+  scope: "Publish typed audit snapshots with redaction, retention, and root-cause traceability."
+}
+
+policy AuditPolicy = public permits {
+  process "node",
+  secret "OPENAI_API_KEY",
+  secret "SEARCH_API_TOKEN"
+}
+
+role AuditWorkerRole = guide: AuditGuide, policy: AuditPolicy, approval: on_request, sandbox: workspace_write
+
+agent auditWorker = AuditWorkerRole
+
+toolserver SearchTools = "mcp" "stdio://search-tools" with AuditPolicy
+
+tool summarizeDraft = SearchTools "summarize_draft" SearchRequest -> SearchResponse
+
+workflow ApprovalFlow = { state : WorkflowState }
+
+auditEnvelope : Empty -> AuditEnvelope
+auditEnvelope req = AuditEnvelope {
+  releaseId = "rel-204",
+  status = "approved"
+}
+
+route releaseAuditRoute = GET "/release/audit" Empty -> AuditEnvelope auditEnvelope
+
+routeEvent : AuditEvent
+routeEvent = AuditEvent {
+  kind = "route",
+  boundary = "releaseAuditRoute",
+  operation = "GET /release/audit",
+  retentionDays = 7,
+  redactedFields = ["authorization"],
+  rootCause = "route releaseAuditRoute",
+  tracePath = ["route releaseAuditRoute", "policy AuditPolicy"]
+}
+
+toolEvent : AuditEvent
+toolEvent = AuditEvent {
+  kind = "tool",
+  boundary = "SearchTools",
+  operation = "summarize_draft",
+  retentionDays = 7,
+  redactedFields = [],
+  rootCause = "tool summarizeDraft",
+  tracePath = ["tool summarizeDraft", "toolserver SearchTools"]
+}
+
+workflowEvent : AuditEvent
+workflowEvent = AuditEvent {
+  kind = "workflow",
+  boundary = "ApprovalFlow",
+  operation = "transition approved",
+  retentionDays = 30,
+  redactedFields = ["rollbackReason"],
+  rootCause = "workflow ApprovalFlow",
+  tracePath = ["workflow ApprovalFlow", "route releaseAuditRoute"]
+}
+
+secretEvent : AuditEvent
+secretEvent = AuditEvent {
+  kind = "secret",
+  boundary = "OPENAI_API_KEY",
+  operation = "resolve",
+  retentionDays = 30,
+  redactedFields = [],
+  rootCause = "OPENAI_API_KEY",
+  tracePath = ["secret OPENAI_API_KEY"]
+}
+
+auditSnapshot : AuditSnapshot
+auditSnapshot = AuditSnapshot {
+  typedEventKinds = ["route", "tool", "workflow"],
+  routeEvent = routeEvent,
+  toolEvent = toolEvent,
+  workflowEvent = workflowEvent,
+  secretEvent = secretEvent,
+  missingSecretBlame = "Missing secret OPENAI_API_KEY"
+}
+
+auditSnapshotJson : Str
+auditSnapshotJson = encode auditSnapshot
+
+main : Str
+main = auditSnapshotJson
